#include <bits/stdc++.h>
using namespace std;
long long n;
long long fib(long long n) {
	long long a[100]={1,1};
	for(long long i=2;i<n;i++){
		a[i]=a[i-1]+a[i-2];
	}
	return a[n-1];
}
int main() {
	cin>>n;
	n=fib(n)%(long long)(pow(2,31));
	cout<<n<<"=";
	for(long long i=2; i*i<=n; i++) {
		while(n%i==0) {
			n/=i;
			if(n==1){
				cout<<i;
				return 0;
			}
			cout<<i<<"*";
		}
	}
	if(n!=1) {
		cout<<n;
	}
	return 0;
}
